// Normalise: uppercase, strip punctuation, collapse spaces.
function norm(s) {
  return String(s || '').toUpperCase().normalize('NFKD')
    .replace(/[^A-Z0-9 ]+/g, ' ').replace(/\s+/g, ' ').trim();
}

const BY_NAME = new Map();   // normalised exact name -> { name, code }
const BY_CODE = new Map();
for (const b of BANKS) { BY_NAME.set(norm(b.name), b); BY_CODE.set(b.code, b); }
const ALIAS_NORM = new Map(); // normalised alias -> normalised target name
for (const k of Object.keys(ALIASES)) ALIAS_NORM.set(norm(k), norm(ALIASES[k]));

// Resolve a bank name (or code) to { code, name } or null if not confident.
function resolveBank(input) {
  if (input == null) return null;
  const raw = String(input).trim();
  if (!raw) return null;
  if (BY_CODE.has(raw)) { const b = BY_CODE.get(raw); return { code: b.code, name: b.name }; }
  const n = norm(raw);
  if (BY_NAME.has(n)) { const b = BY_NAME.get(n); return { code: b.code, name: b.name }; }
  if (ALIAS_NORM.has(n)) { const b = BY_NAME.get(ALIAS_NORM.get(n)); if (b) return { code: b.code, name: b.name }; }
  // last resort: unique startsWith match (avoids ambiguous fintech variants)
  const hits = BANKS.filter(b => norm(b.name).startsWith(n) || n.startsWith(norm(b.name)));
  if (hits.length === 1) return { code: hits[0].code, name: hits[0].name };
  return null;
}

module.exports = { BANKS, resolveBank, normBankName: norm };
